"use client";

import { Icon } from "@/components/shared/icon";
import type {
  TaskCenterViewState,
  TaskIntentSignal,
} from "@/lib/types";
import { cx } from "@/lib/utils";

type TaskIntakePanelProps = {
  value: string;
  onChange: (value: string) => void;
  onPresetSelect: (value: string) => void;
  promptPresets: string[];
  acceptedFileTypes: string[];
  recognizedSignals: TaskIntentSignal[];
  actionLabel: string;
  previewState: TaskCenterViewState;
};

const priorityClassName = {
  high: "border-rose-400/18 bg-rose-400/10 text-rose-100",
  medium: "border-amber-400/18 bg-amber-400/10 text-amber-100",
  low: "border-cyan-400/18 bg-cyan-400/10 text-cyan-100",
} as const;

export function TaskIntakePanel({
  value,
  onChange,
  onPresetSelect,
  promptPresets,
  acceptedFileTypes,
  recognizedSignals,
  actionLabel,
  previewState,
}: TaskIntakePanelProps) {
  const isLoading = previewState === "loading";

  return (
    <section className="panel rounded-[32px] p-6">
      <div className="flex items-start justify-between gap-4">
        <div>
          <p className="text-xs font-semibold uppercase tracking-[0.24em] text-cyan-300/75">
            Natural Language Intake
          </p>
          <h2 className="mt-2 text-xl font-semibold text-white">任务输入区</h2>
          <p className="mt-2 text-sm leading-6 text-[var(--foreground-muted)]">
            输入一句话任务描述，系统先识别任务类型，再推荐后续执行链路。
          </p>
        </div>
        <button
          type="button"
          className="rounded-2xl border border-white/10 bg-white/6 px-4 py-3 text-sm font-semibold text-slate-100 transition hover:border-cyan-400/20 hover:bg-cyan-400/10"
        >
          <span className="inline-flex items-center gap-2">
            <Icon name="upload" className="h-4 w-4" />
            上传文件
          </span>
        </button>
      </div>

      <div className="mt-5 rounded-[28px] border border-white/8 bg-black/12 p-4">
        <textarea
          value={value}
          onChange={(event) => onChange(event.target.value)}
          rows={7}
          className="w-full resize-none bg-transparent text-base leading-7 text-white outline-none placeholder:text-slate-500"
          placeholder="例如：帮我审查这份合同并生成可签署版本，附上高风险条款解释。"
        />
      </div>

      <div className="mt-4 flex flex-wrap gap-2">
        {promptPresets.map((preset) => (
          <button
            key={preset}
            type="button"
            onClick={() => onPresetSelect(preset)}
            className="rounded-full border border-white/10 bg-white/5 px-3 py-2 text-xs font-medium text-slate-200 transition hover:border-cyan-400/18 hover:bg-cyan-400/10 hover:text-cyan-50"
          >
            {preset}
          </button>
        ))}
      </div>

      <div className="mt-6 flex flex-col gap-4 xl:flex-row xl:items-start xl:justify-between">
        <div className="min-w-0 flex-1">
          <p className="text-xs font-semibold uppercase tracking-[0.24em] text-slate-400">
            识别标签
          </p>
          <div className="mt-3 space-y-3">
            {recognizedSignals.map((signal) => (
              <div
                key={signal.id}
                className="rounded-2xl border border-white/8 bg-white/4 px-4 py-3"
              >
                <div className="flex flex-wrap items-center gap-2">
                  <span className="text-sm font-semibold text-white">{signal.label}</span>
                  <span
                    className={cx(
                      "rounded-full border px-2 py-1 text-[11px] font-semibold uppercase tracking-[0.14em]",
                      priorityClassName[signal.priority],
                    )}
                  >
                    {Math.round(signal.confidence * 100)}%
                  </span>
                </div>
                <p className="mt-2 text-sm leading-6 text-[var(--foreground-muted)]">
                  {signal.reason}
                </p>
              </div>
            ))}
          </div>
        </div>

        <div className="w-full max-w-[300px] rounded-[28px] border border-cyan-400/12 bg-cyan-400/6 p-4">
          <p className="text-xs font-semibold uppercase tracking-[0.24em] text-cyan-200/80">
            输入约束
          </p>
          <p className="mt-3 text-sm leading-6 text-cyan-50">
            当前页面先用 mock 上传和任务识别，后续直接接 Dify / FastAPI Intake 接口。
          </p>
          <div className="mt-4 flex flex-wrap gap-2">
            {acceptedFileTypes.map((type) => (
              <span
                key={type}
                className="rounded-full border border-cyan-400/14 bg-black/16 px-3 py-1 text-xs text-cyan-100"
              >
                {type}
              </span>
            ))}
          </div>
          <button
            type="button"
            disabled={isLoading}
            className={cx(
              "mt-5 w-full rounded-2xl border px-4 py-3 text-sm font-semibold transition",
              isLoading
                ? "cursor-wait border-cyan-400/12 bg-cyan-400/8 text-cyan-200/70"
                : "border-cyan-400/20 bg-cyan-400/14 text-cyan-50 hover:bg-cyan-400/20",
            )}
          >
            {actionLabel}
          </button>
        </div>
      </div>
    </section>
  );
}
